import { alpha } from '@mui/material/styles';

export const getCommonStyles = (theme) => ({
  card: {
    height: '100%',
    transition: 'all 0.2s ease-in-out',
    background: theme.palette.mode === 'dark' 
      ? 'linear-gradient(145deg, rgba(41, 49, 79, 0.7), rgba(41, 49, 79, 0.7))'
      : 'linear-gradient(145deg, rgba(255,255,255,0.9), rgba(255,255,255,0.95))',
    backdropFilter: 'blur(10px)',
    border: theme.palette.mode === 'dark'
      ? '1px solid rgba(255,255,255,0.08)'
      : '1px solid rgba(255,255,255,0.5)',
    boxShadow: theme.palette.mode === 'dark'
      ? '0 4px 12px 0 rgba(0,0,0,0.2), 0 2px 4px -1px rgba(0,0,0,0.3)'
      : '0 4px 12px 0 rgba(31,38,135,0.15), 0 2px 4px -1px rgba(31,38,135,0.2)',
    '&:hover': {
      transform: 'translateY(-2px)',
      boxShadow: theme.palette.mode === 'dark'
        ? '0 6px 16px 0 rgba(0,0,0,0.3), 0 3px 6px -2px rgba(0,0,0,0.4)'
        : '0 6px 16px 0 rgba(31,38,135,0.25), 0 3px 6px -2px rgba(31,38,135,0.3)',
    }
  },

  headerCard: {
    background: theme.palette.mode === 'dark' 
      ? 'linear-gradient(90deg, rgba(41, 49, 79, 0.9), rgba(41, 49, 79, 0.9))'
      : 'linear-gradient(90deg, #3949ab 0%, #5e35b1 100%)',
    color: '#fff',
    boxShadow: theme.palette.mode === 'dark'
      ? '0 4px 12px 0 rgba(0,0,0,0.2), 0 2px 4px -1px rgba(0,0,0,0.3)'
      : '0 4px 12px 0 rgba(31,38,135,0.15), 0 2px 4px -1px rgba(31,38,135,0.2)',
    mb: 1.5,
    backdropFilter: 'blur(10px)',
    border: theme.palette.mode === 'dark'
      ? '1px solid rgba(255,255,255,0.08)'
      : '1px solid rgba(255,255,255,0.1)',
  },

  actionButton: {
    borderRadius: 2,
    px: 3,
    background: theme.palette.mode === 'dark' 
      ? 'linear-gradient(45deg, rgba(41, 49, 79, 0.9) 30%, rgba(41, 49, 79, 0.9) 90%)'
      : 'linear-gradient(45deg, #3949ab 30%, #5e35b1 90%)',
    boxShadow: theme.palette.mode === 'dark'
      ? '0 3px 8px 0 rgba(0,0,0,0.2)'
      : '0 3px 8px 0 rgba(31,38,135,0.2)',
    '&:hover': {
      background: theme.palette.mode === 'dark' 
        ? 'linear-gradient(45deg, rgba(41, 49, 79, 1) 20%, rgba(41, 49, 79, 1) 100%)'
        : 'linear-gradient(45deg, #3949ab 20%, #5e35b1 100%)',
      boxShadow: theme.palette.mode === 'dark'
        ? '0 4px 10px 0 rgba(0,0,0,0.3)'
        : '0 4px 10px 0 rgba(31,38,135,0.3)',
    },
  },

  dialog: {
    borderRadius: 2,
    background: theme.palette.mode === 'dark'
      ? 'linear-gradient(145deg, rgba(41, 49, 79, 0.9), rgba(41, 49, 79, 0.9))'
      : '#fff',
    boxShadow: theme.palette.mode === 'dark'
      ? '0 8px 24px 0 rgba(0,0,0,0.3)'
      : '0 8px 24px 0 rgba(31,38,135,0.2)',
  },

  tableContainer: {
    boxShadow: 'none',
    background: 'transparent',
    '& .MuiTableCell-root': {
      borderColor: theme.palette.mode === 'dark' 
        ? 'rgba(255, 255, 255, 0.08)'
        : 'rgba(0, 0, 0, 0.1)',
      color: theme.palette.mode === 'dark'
        ? 'rgba(255, 255, 255, 0.7)'
        : 'inherit',
    }
  },

  chip: {
    primary: {
      borderRadius: 1,
      background: theme.palette.mode === 'dark' 
        ? 'rgba(144, 202, 249, 0.2)'
        : 'rgba(25, 118, 210, 0.1)',
      color: theme.palette.mode === 'dark'
        ? '#90caf9'
        : theme.palette.primary.main,
    },
    success: {
      borderRadius: 1,
      background: theme.palette.mode === 'dark'
        ? 'rgba(76, 175, 80, 0.2)'
        : 'rgba(76, 175, 80, 0.1)',
      color: theme.palette.success.main,
    },
    error: {
      borderRadius: 1,
      background: theme.palette.mode === 'dark'
        ? 'rgba(244, 67, 54, 0.2)'
        : 'rgba(244, 67, 54, 0.1)',
      color: theme.palette.error.main,
    },
    warning: {
      borderRadius: 1,
      background: theme.palette.mode === 'dark'
        ? 'rgba(255, 167, 38, 0.2)'
        : 'rgba(255, 167, 38, 0.1)',
      color: theme.palette.warning.main,
    },
  },

  iconButton: {
    color: 'rgba(255,255,255,0.8)',
    '&:hover': { 
      color: '#fff',
      backgroundColor: 'rgba(255,255,255,0.1)' 
    }
  },

  textField: {
    '& .MuiOutlinedInput-root': {
      '&:hover fieldset': {
        borderColor: 'primary.main',
      },
    },
  },
});
